// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下午六點整。雨聲已經不是「聲」了。它是一面牆。站在教學樓一樓的走廊裡往外看，十公尺以外的校門口就只剩下一團模糊的灰色輪廓，像一幅沒畫完的水墨畫。雨被風切成斜的，從左到右刷過整個視野，連續不斷，沒有間隙。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校門口從來沒有這麼擁擠過。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "讓我進去！我小孩在裡面！", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "先生，請在這邊排隊登記。山路已經進行預警性管制了，目前不開放車輛通行。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "什麼叫不開放？我下午就說要來接人了！是你們學校叫我們早點來的！", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "家長可以進校園等候，但車輛請停在停車場不要移動。山路雨勢太大，公路單位要求全部車輛暫停行駛。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在教學樓側門的屋簷下，離校門口大約三十公尺。雨水從屋簷的邊緣傾瀉下來，形成一道密集的水簾，他必須側著頭、眯著眼才能看清楚外面的情形。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校門口的鐵柵門是全開的，但門外的馬路上停滿了車。私家車、計程車、兩輛轉播車、一輛印著地方電視台標誌的廂型車。車燈在雨幕裡變成一團團暈開的橘黃色光暈，像水裡化開的顏料。有人撐著傘從車裡跑出來，傘被風吹得翻折，雨水從側面打在身上，三秒就濕透了。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "我打過電話了，說可以來接的！", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "登記之後可以進校園等，但車不能開走。抱歉，這是公路單位的規定。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "那我今晚怎麼回去？", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "等雨勢減弱，會通知放行。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個穿著西裝的中年男人站在鐵柵門旁邊，手裡握著一支被雨水打濕的雨傘，傘面朝著一邊歪斜，完全擋不住風。他的領帶鬆了，頭髮貼在額頭上，腳下的皮鞋已經變成了兩灘移動的水窪。他對著手機大聲說了幾句什麼，聲音被雨聲和風聲切成碎片，只聽得到最後兩個字：「⋯⋯馬上！」", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著這一切。校門口的人越聚越多，有些是家長，有些是穿著反光背心的校慶志工，有些是拿著攝影設備的媒體人員。他們全部被雨困在同一個狹窄的區域裡——門內是校園，門外是封閉的山路，哪裡都去不了。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)山路封了。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)進不來，出不去。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這座校園變成了一個密閉的容器。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)百年校慶。精彩。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個撐傘的家長從他身邊擠過去，傘骨戳到了他的肩膀。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "借過。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從側門走出來，沿著教學樓外牆的走廊往校門口的方向走。走廊有屋簷遮雨，但風會把雨水斜斜地甩進來，地面上積了一層薄薄的水，踩上去會發出濕鞋底特有的那種「嘰」聲。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走了一半，他看到了邵叔。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔站在校門口右側的臨時指揮帳篷底下。帳篷是深藍色的，有金屬支架撐著，頂上積了一灘雨水讓布面微微凹陷，兩側拉起了透明的遮雨布。帳篷下面放著一張摺疊桌，桌上攤著一張校園平面圖和幾份文件。兩名穿著制服的警察站在帳篷外面，正在引導一位撐傘的家長填寫登記表。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的姿態和周圍的慌亂形成了鮮明的對比。他穿著一件深色的防風雨衣，帽子沒有拉上，頭髮被雨水打濕了但沒有亂。他站在桌邊，一只手按在平面圖上，另一只手拿著對講機，偶爾說幾句話。聲音聽不見，但看得出是短促、平穩、有條理的那種——他不是在下達命令，而是在確認情況。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "警察先生，我小孩在宿舍那邊，能不能讓我過去？", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "可以。走這條路穿過操場，到第二棟教學樓右轉就到了。路上注意安全，積水比較深的地方繞著走。", background: "chapter_1/ch1_act7_s0", portrait: "邵啟明/base" },
    { characterId: CharacterId.Parent, character: "家長", dialogue: "好，好，謝謝。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "家長的語氣在邵叔回答之後明顯鬆了一口氣。這很正常。邵叔有那種讓人安心的特質——聲音不高不低，語速不快不慢，眼睛會看著你說話。在混亂的場合裡，這種穩定的存在感比任何指令都有效。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔在指揮。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他站在那裡，整個校門口的秩序就在那裡。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果不知道那條訊息的事，我會覺得這是最讓人放心的畫面。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在走廊的柱子後面，沒有走過去。不是刻意躲，是因為他看到了另一個人。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任從停車場的方向走過來。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的樣子和邵叔完全是兩個極端。他的頭髮亂了，襯衫的領口解開了兩顆扣子，手裡握著的手機螢幕亮著，手指在上面反覆滑動。他走路的速度很快，但方向不定——往帳篷走了兩步，又停住，回頭看了一眼停車場，然後又轉回來繼續走。像一隻找不到出口的蛾。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任走到帳篷底下的時候，邵叔抬起頭看了他一眼。那一眼很短，短到如果不是顧言一直在看，根本不會注意到。但在那一眼裡，邵叔的手指在平面圖上停了一下，然後他把對講機放到了桌上。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任走到邵叔身邊，彎下腰，湊近他的耳朵。距離很近，近到兩個人的肩膀幾乎貼在一起。林主任的嘴唇在動。他在說話，但聲音壓得極低，低到在三十公尺外的顧言什麼都聽不見。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在跟邵叔說什麼？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的手在比劃。不是那種為了強調語氣的比劃，而是一種焦躁的、無序的動作——手指指向停車場的方向，又指向校門，又指向自己的手機，然後攤開雙手，肩膀聳起來。整個肢體語言都在說同一句話：出了問題，我不知道怎麼辦。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的反應和林主任完全不同。他沒有比劃，沒有站起來，沒有改變姿勢。他只是微微偏了一下頭，聽林主任說完，然後伸出手，在林主任的肩膀上拍了兩下。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拍得很穩。不是安慰的那種輕拍，是那種「我知道了，你聽我說」的節奏。一下。兩下。然後他的手留在林主任的肩膀上，嘴唇靠近對方的耳朵，說了幾句什麼。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔在安撫他。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有人看到這一幕，都會覺得是一個經驗豐富的警察在穩定一個焦慮的校方人員。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但林主任焦慮的不是天氣。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看到林主任在邵叔說完之後深吸了一口氣。那個呼吸的動作很大，大到胸口起伏明顯可見。然後林主任點了點頭，站直身體，整理了一下自己的領口，轉身往行政樓的方向走去。走路的姿勢比來的時候平穩了一些，但手指還是在無意識地搓著手機的邊緣。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔目送他離開，然後重新拿起了對講機。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們在說什麼？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任從停車場方向過來。停車場裡有媒體車輛。他在看手機。他焦躁、不安、來回踱步。他找邵叔，壓低聲音說話。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是一個學校主任該有的反應。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)山路封了，校門關了，所有人被困在校園裡。如果林主任有什麼不想讓別人看到的東西——或者什麼人——這個時間點對他來說是最危險的。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所以他去找邵叔。不是去找警察求助。是去找邵叔。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他的焦慮不是因為失控，是因為計畫正在被天氣打亂。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個想法讓他的胃收縮了一下。不是確定，只是一種直覺性的聯結。林主任的焦慮和邵叔的平靜之間有一條線，他看不到那條線的全貌，但他知道它在。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有繼續走近。他沿著走廊退回到教學樓的轉角處，靠著牆站了一會兒。雨從屋簷的縫隙裡飛進來，打在他的手背上，冰涼的。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)冷靜。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也許林主任只是因為校慶活動被打亂而焦慮。他負責整個活動的後勤和場地安排，天氣突變讓他的計畫全部亂了。這很正常。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但如果只是這樣，他不需要壓低聲音跟邵叔說話。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他可以去指揮室求助。可以打電話給上級。可以跟在場的任何一個警察說。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他偏偏找了邵叔。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一陣風從校門口的方向刮過來，帶著雨水的重量撞在建築物的外牆上，發出一聲沉悶的撞擊。走廊上的積水被風吹出一層細小的波紋，波紋在腳邊碎開。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "停車場那邊，一輛轉播車的側門開著，有人從裡面探出半個身子，舉著攝影機拍校門口的混亂場面。雨水打在鏡頭上，畫面一定是模糊的，但他們還在拍。這是新聞人的直覺——混亂本身就是素材。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)媒體也在裡面。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)山路封了，他們也走不了。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們的攝影機、他們的鏡頭，全部被困在這座校園裡。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果今晚真的發生什麼事，他們會拍到。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個念頭剛浮起來，就被另一個念頭壓了下去。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)或者，也許這正是某些人不怕今晚發生什麼的原因。媒體在這裡。拍到什麼都可以被改。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼睛，後腦勺抵著潮濕的牆壁。雨聲像一塊巨大的布，把所有的聲音都裹在裡面——腳步聲、說話聲、引擎聲、風聲——全部混成一團低沉的嗡鳴。他分不清哪些聲音來自外面，哪些來自自己的心跳。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在想太多了。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔是警察。林主任是學校的人。他們在颱風天討論活動安排，這有什麼問題？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)可是林主任的表情不對。那不是「活動被打亂」的焦慮。那是一個人在擔心某件具體的事情被揭穿時才有的表情。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而邵叔拍他肩膀的動作也不對。那不是安慰。那是控制。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那兩下拍肩是在說：冷靜，一切在我掌握之中。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)掌握什麼？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他睜開眼睛。視線穿過走廊的柱子和雨幕，再次落在校門口的帳篷上。邵叔還站在那裡，正在和一個穿反光背心的志工說話，手指指向操場的方向，似乎在安排避雨的集合點。他的動作流暢、自信，像一個人對整個校園的每一吋空間都瞭如指掌。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔今天一整天都在這裡。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他比任何人都清楚這座校園的所有出口、所有死角、所有攝影機拍不到的地方。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果山路被封，校門被管，所有人都被困在校園裡——", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那他比任何人都清楚，沒有人能離開。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一輛廂型車的喇叭突然響了一聲，尖銳刺耳，穿透了雨幕。有人在大聲喊叫，聽不清內容，但語氣是憤怒的。校門口的混亂還在繼續——家長在排隊登記，警察在維持秩序，媒體在拍攝，雨在下。所有的聲音疊在一起，像一座正在倒塌的積木塔。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但在混亂的中心，邵叔是安靜的。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他站在那裡，什麼都不怕。所有人都信他。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但如果他就是那個製造風暴的人呢？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯不，我在亂想。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔不會傷害我。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)可是那條訊息是真的。校史館的照片是真的。許星棠的警告是真的。林主任剛才的表情是真的。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有什麼東西正在發生。我不知道是什麼，但它正在發生。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從牆邊站直身體，沿著走廊往回走。經過一樓樓梯間的時候，他停了一下，轉頭看向窗外。窗外是停車場的方向。停車場裡的車輛全部靜止不動，雨打在車頂上，沿著車身流下來，在地面上匯成淺淺的水流。兩輛轉播車的車身被雨水洗得發亮，電視台的標誌在水膜下面像一隻半睜的眼睛。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有的車都停著。所有的人都留著。所有的出口都關著。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這座校園，從一所學校變成了一個容器。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)六點了。天很快就會黑。天黑之後，雨會更大，山路不會開放，所有人會被留在這裡過夜。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果今晚真的有人要對我做什麼——", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我跑不掉。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是他今天第一次清楚地意識到這件事。不是推理，不是猜測，是一種身體層面的認知。就像你站在一個房間裡，突然注意到門已經鎖上了，窗戶打不開，牆壁很厚。你不害怕，因為還沒有發生什麼事。但你感受到了空間的邊界。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不會有人真的要殺我。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人用我爸的案子在嚇我。也許是許星棠，也許是韓越，也許是某個我還不知道的人。他們想知道我爸留下了什麼，或者他們想用我來引出什麼。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但不會有人真的動手。這不是電影。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯對吧？", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨繼續下。校門口的廣播喇叭發出一聲刺耳的回授音，然後傳出另一條廣播：「各活動區域注意，晚間閉幕典禮提前至十八點三十分於禮堂舉行，請所有人員⋯⋯」後面的內容被雨聲吞掉了。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉身走上樓梯。腳步聲在空蕩的樓梯間裡產生回音，一層一層地向上傳遞，像有人在樓上跟著他走。他沒有回頭。", background: "chapter_1/ch1_act7_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十八點三十分。閉幕典禮。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有人都會集中在禮堂。邵叔會在指揮室。林主任會在後台。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而我會找一個他們都看不到的地方，把所有的事情再想一遍。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)在二十二點二十二分之前，我必須搞清楚這座校園裡到底發生過什麼。", background: "chapter_1/ch1_act7_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到二樓的走廊盡頭，推開了一扇通往露台的門。露台上沒有人，地面全是積水，天空是一塊完整的鉛灰色幕布，看不見雲的邊界，也看不見雲的厚度。只有雨。從天上落到地上。從所有方向同時落下來。", background: "chapter_1/ch1_act7_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我出不去。", background: "chapter_1/ch1_act7_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我不打算逃。", background: "chapter_1/ch1_act7_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我要知道真相。", background: "chapter_1/ch1_act7_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在露台上，雨水打在他的臉上，流過眉毛和睫毛，模糊了視線。遠處，鐘樓在雨中沉默。它從來不移動，從來不回答。它只是站在那裡，指針在雨幕後面看不見的地方走著，一步一步，朝向二十二點二十二分。", background: "chapter_1/ch1_act7_s1" },
];
